import{_ as s,o as r,c as t,a2 as i}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"Réglementation & QR","description":"","frontmatter":{"title":"Réglementation & QR"},"headers":[],"relativePath":"docs/fr/advertisers/sponsored-mail/design-guide/legal.md","filePath":"docs/fr/advertisers/sponsored-mail/design-guide/legal.md"}'),o={name:"docs/fr/advertisers/sponsored-mail/design-guide/legal.md"};function a(d,e,n,l,p,c){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="mentions-legales-et-qr-codes" tabindex="-1">Mentions Légales et QR Codes <a class="header-anchor" href="#mentions-legales-et-qr-codes" aria-label="Permalink to &quot;Mentions Légales et QR Codes&quot;">​</a></h1><p>Respectez ces obligations pour valider votre campagne et garantir un tracking performant.</p><hr class="my-6"><h2 class="text-purple-200 mb-4">🤖 Tout savoir sur le QR Code</h2><div style="border:2px solid #d73a49;background-color:#fff5f5;border-radius:8px;padding:24px;margin-bottom:30px;"><div style="display:flex;gap:20px;align-items:start;"><div style="font-size:30px;">⚠️</div><div><h3 class="mt-0 text-red-200">Pourquoi le QR Code getinside est obligatoire ?</h3><p class="mb-2">Nous ne pouvons pas accepter un QR code généré par vos soins. Vous devez impérativement intégrer le fichier <code>.svg</code> fourni par notre plateforme.</p><ul class="mb-0 pl-4 fs-3"><li><strong>Preuve de distribution :</strong> C&#39;est grâce aux scans de ce QR code unique que nous certifions que la campagne a bien été distribuée par l&#39;e-commerçant.</li><li><strong>Monitoring :</strong> Il nous permet de détecter les anomalies de distribution en temps réel.</li></ul></div></div></div><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(300px, 1fr));gap:20px;margin-bottom:40px;"><div style="border:1px solid #2563eb;border-radius:8px;padding:20px;background:#eff6ff;"><h3 class="mt-0 text-purple-200">✨ La magie du &quot;Dynamique&quot;</h3><p class="fs-2 text-grey-dk-000">Nos QR codes sont dynamiques. Cela signifie que l&#39;URL de redirection n&#39;est pas &quot;gravée&quot; dans le motif du code.</p><div style="background:var(--vp-c-bg-elv);padding:10px;border-radius:4px;border:1px solid var(--vp-c-divider);margin-top:10px;"><strong>Avantage :</strong> Vous pouvez changer l&#39;URL de destination (Landing Page) à tout moment via la plateforme, <strong>même après l&#39;impression des flyers</strong>. Idéal pour corriger une erreur ou prolonger une offre. </div></div><div style="border:1px solid #2da44e;border-radius:8px;padding:20px;background:#f0fcf4;"><h3 class="mt-0 text-green-200">🎯 Tracking &amp; Performance</h3><p class="fs-2 text-grey-dk-000">getinside compte les <strong>Scans</strong>. Pour compter les <strong>Ventes</strong> dans votre Google Analytics, vous devez configurer votre URL.</p><div style="background:var(--vp-c-bg-elv);padding:10px;border-radius:4px;border:1px solid #2da44e;margin-top:10px;font-size:0.9em;"><strong>Conseil :</strong> Ne mettez pas <code>monsite.com</code>.<br> Mettez <code>monsite.com?utm_source=getinside&amp;utm_medium=asile-colis</code>. </div></div></div><h2 class="text-blue-200 mb-4">⚠️ Mentions Légales &amp; Logos</h2><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);margin-bottom:40px;"><div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:20px;margin-bottom:20px;"><p class="fs-4 mt-0 mb-0">Éléments graphiques obligatoires à intégrer :</p><a href="https://drive.google.com/drive/folders/1ORm6uAhsIWCCFWhOl-NjO4tKfiGQdLNy" target="_blank" class="btn btn-primary btn-sm">⬇️ Télécharger le pack Logos</a></div><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(200px, 1fr));gap:20px;"><div><strong>1. Identification</strong><br><span class="fs-2 text-grey-dk-000">Nom social, Forme juridique, Capital, Ville &amp; RCS de l&#39;annonceur.</span></div><div><strong>2. Logos Environnement</strong><br><span class="fs-2 text-grey-dk-000">Cartouche Info-tri (Triman) + Logo getinside (disponibles via le bouton ci-dessus).</span></div><div><strong>3. CGV de l&#39;offre</strong><br><span class="fs-2 text-grey-dk-000">Dates de validité et conditions (ex: &quot;valable dès 50€ d&#39;achat&quot;).</span></div></div></div><h2 class="text-grey-dk-000 mt-6 mb-4">⚖️ Spécificités Sectorielles</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(300px, 1fr));gap:20px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><h3 class="mt-0 fs-4">🍷 Alcool</h3><p class="mb-2"><em>&quot;L&#39;abus d&#39;alcool est dangereux pour la santé, à consommer avec modération.&quot;</em></p><span class="fs-2 text-grey-dk-000">Loi Evin (Art. L3323-4). Interdiction ciblage mineurs.</span></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><h3 class="mt-0 fs-4">🥗 Alimentation</h3><p class="mb-2"><em>&quot;Pour votre santé, mangez au moins cinq fruits et légumes par jour.&quot;</em></p><span class="fs-2 text-grey-dk-000">Mangez-bougez.fr (Art. L2133-1).</span></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><h3 class="mt-0 fs-4">🚗 Automobile</h3><p class="mb-2">Message mobilité douce : <em>&quot;Pensez à covoiturer.&quot;</em></p><span class="fs-2 text-grey-dk-000">Et classe énergétique CO2 (Arrêté 2018).</span></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><h3 class="mt-0 fs-4">💰 Crédit / Finance</h3><p class="mb-2"><em>&quot;Un crédit vous engage et doit être remboursé. Vérifiez vos capacités...&quot;</em></p></div></div>',10)])])}const u=s(o,[["render",a]]);export{m as __pageData,u as default};
